const data = $input.first().json;

// supports multiple webhook formats
const input =
  data.allRecords?.[0]?.body ||
  data.body ||
  data;

// fallback safety
if (!input) {
  throw new Error("No input received");
}

// If it's already a single record → wrap it into array
const records = Array.isArray(input)
  ? input
  : [input];

const allowedModalities = ['MRI', 'CT', 'PET', 'XRAY'];
const results = [];
const seenRecords = new Map();

for (const record of records) {
  const issues = [];
  let status = 'VALID';
  let qualityFlag = 'GOOD';

  // Required fields
  if (!record.patient_id) {
    issues.push('Missing required field: patient_id');
    status = 'INVALID';
  }
  if (!record.study_date) {
    issues.push('Missing required field: study_date');
    status = 'INVALID';
  }
  if (!record.modality) {
    issues.push('Missing required field: modality');
    status = 'INVALID';
  }

  // Validate date
  if (record.study_date) {
    const dateStr = String(record.study_date);
    const regex = /^\d{8}$/;

    if (!regex.test(dateStr)) {
      issues.push('study_date must be YYYYMMDD');
      status = 'INVALID';
    } else {
      const year = +dateStr.slice(0,4);
      const month = +dateStr.slice(4,6);
      const day = +dateStr.slice(6,8);

      const studyDate = new Date(year, month - 1, day);
      const today = new Date();
      today.setHours(0,0,0,0);

      if (studyDate > today) {
        issues.push('study_date cannot be in future');
        status = 'INVALID';
      }
    }
  }

  // Modality check
  if (record.modality && !allowedModalities.includes(record.modality)) {
    issues.push('Invalid modality');
    status = 'INVALID';
  }

  // Duplicate check
  if (record.patient_id && record.study_date) {
    const key = `${record.patient_id}_${record.study_date}`;

    if (seenRecords.has(key)) {
      issues.push('Duplicate record');
      status = 'WARNING';
      qualityFlag = 'DUPLICATE';
    } else {
      seenRecords.set(key, true);
    }
  }

  if (status === 'INVALID') {
    qualityFlag = 'BAD';
  }

  const cleanedSummary =
    `Patient ${record.patient_id || 'UNKNOWN'} | ${record.modality || 'UNKNOWN'} | ${record.study_date || 'UNKNOWN'}`;

  results.push({
    status,
    issues,
    cleaned_summary: cleanedSummary,
    patient_id: record.patient_id || null,
    modality: record.modality || null,
    quality_flag: qualityFlag
  });
}

return results.map(r => ({ json: r }));
